import { useState, useEffect } from "react";
import { recipeAPI, authAPI } from "../../services/api";
import CreateRecipeModal from "../../components/CreateRecipeModal";

const NAV = [
  { icon: "📊", label: "Dashboard", id: "overview" },
  { icon: "👨‍🍳", label: "My Creations", id: "creations" },
  { icon: "📈", label: "Analytics", id: "analytics" },
  { icon: "👥", label: "Followers", id: "followers" },
];

const TABS = ["All Recipes", "Live", "Pending Review", "Rejected"];

const STATUS_BADGE = {
  Live: "badge-live",
  "Pending Review": "badge-pending",
  Rejected: "badge-rejected",
};

export default function ChefDashboardPage({ setPage, setSelectedRecipe, user }) {
  const [activeNav, setActiveNav] = useState("creations");
  const [activeTab, setActiveTab] = useState("All Recipes");
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showAddUserModal, setShowAddUserModal] = useState(false);
  const [formData, setFormData] = useState({ name: "", email: "", password: "", role: "user" });
  const [formErrors, setFormErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    fetchMyRecipes();
  }, []);

  const fetchMyRecipes = async () => {
    try {
      setLoading(true);
      const response = await recipeAPI.getMyRecipes();
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching chef recipes:", err);
    } finally {
      setLoading(false);
    }
  };

  const filtered = activeTab === "All Recipes" 
    ? recipes 
    : recipes.filter(r => r.status === activeTab);

  return (
    <div className="sidebar-layout">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <div style={{ padding: "0 8px 32px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "32px" }}>
            <div style={{ width: "32px", height: "32px", background: "var(--primary)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px", color: "#fff" }}>🍽</div>
            <span className="serif" style={{ fontSize: "18px", fontWeight: "700", color: "var(--navy)" }}>RecipeNest</span>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
            {NAV.map(item => (
              <button 
                key={item.id} 
                className={`sidebar-item ${activeNav === item.id ? "active" : ""}`} 
                onClick={() => setActiveNav(item.id)}
              >
                <span style={{ fontSize: "18px" }}>{item.icon}</span>
                {item.label}
              </button>
            ))}
          </div>
        </div>

        <div style={{ marginTop: "auto", padding: "20px 8px 0", borderTop: "1px solid var(--border-light)" }}>
          <button className="sidebar-item" style={{ marginBottom: "16px" }}>
            <span style={{ fontSize: "18px" }}>⚙️</span> Settings
          </button>

          <div style={{ display: "flex", alignItems: "center", gap: "12px", padding: "12px", background: "var(--bg)", borderRadius: "var(--radius-md)", marginBottom: "16px", border: "1px solid var(--border-light)" }}>
            <div className="sidebar-avatar" style={{ width: "40px", height: "40px", fontSize: "14px", fontWeight: "700", background: "var(--primary)", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "10px" }}>CM</div>
            <div>
              <div style={{ fontSize: "13px", fontWeight: "700", color: "var(--text-main)" }}>Chef Mario</div>
              <div style={{ fontSize: "11px", color: "var(--text-muted)" }}>Master Chef</div>
            </div>
          </div>

          <button className="logout-btn" onClick={() => setPage("home")}>
            <span>🚪</span> Logout
          </button>
        </div>
      </aside>

      {/* DASHBOARD CONTENT */}
      <main className="page-content" style={{ background: "var(--bg)" }}>
        <div className="page-header" style={{ marginBottom: "40px" }}>
          <div>
            <h1 className="page-title">My Creations</h1>
            <p className="page-sub">Manage your portfolio and track how your recipes are performing.</p>
          </div>
          <button 
            className="action-cta" 
            style={{ filter: "drop-shadow(0 4px 12px rgba(255, 49, 49, 0.2))" }}
            onClick={() => setIsModalOpen(true)}
          >
            <span style={{ fontSize: "18px" }}>+</span> Create New Recipe
          </button>
        </div>

        {/* Stats Row */}
        <div className="stats-row" style={{ marginBottom: "48px" }}>
          {[
            { label: "Total Followers", val: "12.5k", icon: "👥", bg: "rgba(59, 130, 246, 0.1)", color: "#3b82f6" },
            { label: "Recipe Likes", val: "45.8k", icon: "❤️", bg: "rgba(239, 68, 68, 0.1)", color: "#ef4444" },
            { label: "Average Rating", val: "4.8", icon: "⭐", bg: "rgba(234, 179, 8, 0.1)", color: "#eab308" }
          ].map((stat, i) => (
            <div key={i} className="stat-card" style={{ border: "1px solid var(--border-light)", boxShadow: "var(--shadow-sm)" }}>
              <div className="stat-icon" style={{ background: stat.bg, color: stat.color }}>{stat.icon}</div>
              <div>
                <div className="stat-val">{stat.val}</div>
                <div className="stat-label">{stat.label}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div className="tab-bar" style={{ marginBottom: "32px", borderBottom: "1px solid var(--border-light)" }}>
          {TABS.map(tab => (
            <button 
              key={tab} 
              className={`tab-btn ${activeTab === tab ? "active" : ""}`} 
              onClick={() => setActiveTab(tab)}
              style={{ padding: "12px 24px" }}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Recipe Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "24px" }}>
          {filtered.map(recipe => (
            <div 
              key={recipe.id} 
              className="card-hover"
              style={{ background: "var(--white)", borderRadius: "var(--radius-lg)", overflow: "hidden", border: "1px solid var(--border-light)", cursor: "pointer", transition: "var(--transition)" }}
            >
              <div style={{ position: "relative", height: "180px" }}>
                <img src={recipe.image} alt={recipe.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                <span className={`badge ${STATUS_BADGE[recipe.status]}`} style={{ position: "absolute", top: "12px", left: "12px", border: "1px solid rgba(0,0,0,0.05)" }}>
                  ● {recipe.status}
                </span>
              </div>
              <div style={{ padding: "20px" }}>
                <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "4px" }}>{recipe.title}</h3>
                <p style={{ fontSize: "12px", color: "var(--text-muted)" }}>Updated {recipe.updatedAgo}</p>
              </div>
              <div style={{ display: "flex", gap: "8px", padding: "0 20px 20px" }}>
                {[
                  { icon: "✏️", label: "Edit" },
                  { icon: "📊", label: "Stats" },
                  { icon: "🗑️", label: "Delete" }
                ].map(action => (
                  <button 
                    key={action.label}
                    style={{ 
                      flex: 1, 
                      background: "var(--bg)", 
                      border: "1px solid var(--border-light)", 
                      padding: "8px", 
                      borderRadius: "8px", 
                      fontSize: "14px",
                      transition: "var(--transition)"
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = "rgba(255,49,49,0.05)"}
                    onMouseLeave={e => e.currentTarget.style.background = "var(--bg)"}
                  >
                    {action.icon}
                  </button>
                ))}
              </div>
            </div>
          ))}

          {/* New Draft Placeholder */}
          <div style={{ 
            background: "var(--white)", 
            border: "2px dashed var(--border-light)", 
            borderRadius: "var(--radius-lg)", 
            display: "flex", 
            flexDirection: "column", 
            alignItems: "center", 
            justifyContent: "center", 
            minHeight: "300px", 
            padding: "40px",
            textAlign: "center"
          }}>
            <div style={{ width: "56px", height: "56px", background: "var(--bg)", borderRadius: "16px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "24px", marginBottom: "20px" }}>➕</div>
            <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "8px" }}>New Idea?</h3>
            <p style={{ fontSize: "13px", color: "var(--text-muted)", marginBottom: "24px", lineHeight: "1.5" }}>Start drafting your next culinary masterpiece and share it with the world.</p>
            <button className="btn-secondary" style={{ padding: "8px 24px", fontSize: "13px" }} onClick={() => setIsModalOpen(true)}>New Draft</button>
          </div>
        </div>

        <CreateRecipeModal 
          isOpen={isModalOpen} 
          onClose={() => setIsModalOpen(false)} 
          onRefresh={fetchMyRecipes} 
        />
      </main>
    </div>
  );
}
